public class ArithmeticDemo {
    public static void main(String[] args) {
        int a = 10, b = 3;
        System.out.println(a + b);   // 13
        System.out.println(a - b);   // 7
        System.out.println(a * b);   // 30
        System.out.println(a / b);   // 3 (NOT 3.33!)
        System.out.println(a % b);   // 1 (remainder)
        double c = 10.0;
        System.out.println(c / b);   // 3.333...
    }
}

public class CompareDemo {
    public static void main(String[] args) {
        int age = 20, limit = 18;
        System.out.println(age == limit);  // false
        System.out.println(age != limit);  // true
        System.out.println(age > limit);   // true
        System.out.println(age >= 20);     // true
        String a = new String("hi");
        String b = new String("hi");
        System.out.println(a == b);       // false!
        System.out.println(a.equals(b));  // true
    }
}

public class LogicalDemo {
    public static void main(String[] args) {
        boolean ticket = true, onTime = false;
        System.out.println(ticket && onTime);  // false
        System.out.println(ticket || onTime);  // true
        System.out.println(!ticket);           // false
        // Short-circuit safety:
        int x = 0;
        if (x != 0 && 10/x > 2) { } // Safe! Division skipped
    }
}

public class AssignDemo {
    public static void main(String[] args) {
        int score = 100;
        score += 25;  // 125
        score -= 10;  // 115
        score *= 2;   // 230
        score /= 5;   // 46
        score %= 10;  // 6
        System.out.println(score);  // 6
        String msg = "Hello";
        msg += " World";
        System.out.println(msg);  // Hello World
    }
}

public class UnaryDemo {
    public static void main(String[] args) {
        int x = 5;
        int a = x++;  // a=5 (old), x=6
        int b = ++x;  // x=7, b=7 (new)
        System.out.println(a + " " + b);  // 5 7
        System.out.println(-42);   // negate
        System.out.println(!true); // false
    }
}

public class TernaryDemo {
    public static void main(String[] args) {
        int age = 20;
        String s = (age >= 18) ? "Adult" : "Minor";
        System.out.println(s);  // Adult
        int x = 15, y = 23;
        int max = (x > y) ? x : y;
        System.out.println(max);  // 23
    }
}

public class PrecDemo {
    public static void main(String[] args) {
        System.out.println(2 + 3 * 4);    // 14 (not 20!)
        System.out.println((2 + 3) * 4);  // 20
        boolean r = 5 > 3 && 2 < 4 || false;
        System.out.println(r);  // true
    }
}

public class IntDivTrap {
    public static void main(String[] args) {
        System.out.println(7 / 2);          // 3
        System.out.println(7.0 / 2);        // 3.5
        System.out.println((double)7 / 2);  // 3.5
        int c=17, t=20;
        System.out.println((c/t)*100);        // 0!
        System.out.println((c*100.0)/t);      // 85.0
    }
}

public class ConcatDemo {
    public static void main(String[] args) {
        System.out.println(3 + 2);           // 5
        System.out.println("Sum: " + 3 + 2); // Sum: 32
        System.out.println("Sum: " + (3+2)); // Sum: 5
        System.out.println(1 + 2 + " cats"); // 3 cats
        System.out.println("cats " + 1 + 2); // cats 12
    }
}

public class BitwiseDemo {
    public static void main(String[] args) {
        System.out.println(5 & 3);    // 1 (0101 & 0011 = 0001)
        System.out.println(5 | 3);    // 7 (0101 | 0011 = 0111)
        System.out.println(5 ^ 3);    // 6 (0101 ^ 0011 = 0110)
        System.out.println(5 << 1);   // 10 (5 * 2)
        System.out.println(20 >> 1);  // 10 (20 / 2)
    }
}

public class InstanceDemo {
    public static void main(String[] args) {
        String text = "Hello";
        System.out.println(text instanceof String);  // true
        System.out.println(text instanceof Object);  // true
        String empty = null;
        System.out.println(empty instanceof String); // false
    }
}

public class Mistakes {
    public static void main(String[] args) {
        // == vs .equals()
        String a = new String("hi"), b = new String("hi");
        System.out.println(a == b);       // false!
        System.out.println(a.equals(b));  // true
        // Division by zero guard
        int d = 0;
        if (d != 0) System.out.println(10/d);
        else System.out.println("Cannot divide by zero!");
    }
}

