public class ShortCircuit {
    public static void main(String[] args) {
        int d = 0;
        if (d != 0 && 10/d > 2) {
            System.out.println("Big result");
        } else {
            System.out.println("Safe! No crash.");
        }
        if (true || expensiveCheck()) {
            System.out.println("Skipped expensive check");
        }
    }
    static boolean expensiveCheck() {
        System.out.println("This never runs"); return false;
    }
}

public class Perms {
    static final int R=1, W=2, X=4, ADMIN=8;
    public static void main(String[] args) {
        int p = R|W;  // 3
        System.out.println("Has write: "+((p&W)!=0));
        System.out.println("Is admin: "+((p&ADMIN)!=0));
        p |= X;       // add execute -> 7
        p &= ~W;      // remove write -> 5
        System.out.println("Final: "+p);
    }
}

public class Bill {
