        double bill=87.50; int people=4; double tipPct=15;
        double tip = bill*tipPct/100;
        double total = bill+tip;
        double pp = total/people;
        System.out.printf("Per person: %.2f%n", pp);
        String ok = pp <= 30 ? "Within budget" : "Over!";
        System.out.println(ok);
    }
}

public class Clock {
    public static void main(String[] args) {
        System.out.println("10PM+5h = "+((22+5)%24)+":00");
        String[] days={"Sun","Mon","Tue","Wed","Thu","Fri","Sat"};
        System.out.println("Wed+10d = "+days[(3+10)%7]);
        for(int i=0;i<9;i++) System.out.println("Item"+i+" -> Team"+(i%3));
    }
}

public class Prec {
    public static void main(String[] args) {
        System.out.println(2+3*4-1);    // 13
        System.out.println((2+3)*(4-1));// 15
        System.out.println(5>3 && 2+2==4 || false); // true
        int x=5; int r=x++ * 2 + --x;
        System.out.println(r+" x="+x);  // 15 x=5
    }
}

public class Leap {
    public static void main(String[] args) {
        int[] years={2000,1900,2024,2023,2100};
        for(int y:years) {
            boolean leap = (y%4==0) && (y%100!=0 || y%400==0);
            System.out.println(y+": "+(leap?"LEAP":"not"));
        }
    }
}

public class Cast {
    public static void main(String[] args) {
        int i=42; double d=i;  // auto widening
        System.out.println(d);  // 42.0
        double pi=3.14; int t=(int)pi;  // manual narrowing
        System.out.println(t);  // 3
        System.out.println((double)7/2);  // 3.5
        byte b=(byte)300;  // overflow!
        System.out.println(b);  // 44
        System.out.println((int)'A');  // 65
    }
}

